inline auto MainWindow::show () -> void{
    window().show();
}

inline auto MainWindow::hide () -> void{
    window().hide();
}

inline auto MainWindow::window () const -> slint::Window&{
    return m_globals.window();
}

inline auto MainWindow::run () -> void{
    show();
    slint::run_event_loop();
    hide();
}
